code: def get(self, request: Dict[str, Any], ignored_args_for_cache_key: Optional[list[str]] = None) -> Any:
    if self.enable_disk_cache:
        # Lazily purge expired entries so disk usage/eviction accounting stays accurate.
        self.disk_cache.expire()

    try:
        key = self.cache_key(request, ignored_args_for_cache_key)
    except Exception:
        logger.debug(f"Failed to generate cache key for request: {request}")
        return None

    if self.enable_memory_cache and key in self.memory_cache:
        with self._lock:
            response = self.memory_cache[key]
    elif self.enable_disk_cache and key in self.disk_cache:
        # Found on disk but not in memory cache, add to memory cache
        response = self.disk_cache[key]
        response = self._decode_disk_value(response)
        if self.enable_memory_cache:
            with self._lock:
                self.memory_cache[key] = response
    else:
        return None

    response = copy.deepcopy(response)
    if hasattr(response, "usage"):
        # Clear the usage data when cache is hit, because no LM call is made
        response.usage = {}
    return response

def put(
    self,
    request: Dict[str, Any],
    value: Any,
    ignored_args_for_cache_key: Optional[list[str]] = None,
    enable_memory_cache: bool = True,
) -> None:
    try:
        key = self.cache_key(request, ignored_args_for_cache_key)
    except Exception:
        logger.debug(f"Failed to generate cache key for request: {request}")
        return

    if self.enable_memory_cache and enable_memory_cache:
        with self._lock:
            self.memory_cache[key] = value

    if self.enable_disk_cache:
        try:
            disk_value = self._encode_disk_value(value) if self.compress else value
            if self.ttl is not None:
                self.disk_cache.set(key, disk_value, expire=self.ttl)
            else:
                self.disk_cache[key] = disk_value
        except Exception as e:
            # Disk cache writing can fail for different reasons, e.g. disk full or the `value` is not picklable.
            logger.debug(f"Failed to put value in disk cache: {value}, {e}")
note: adds lazy expire() purge at top of get() per your TTL design; put() uses disk_cache.set(key,value,expire=ttl) when ttl set, else plain assignment; both wrap value through _encode_disk_value/_decode_disk_value helpers (compress feature, no-op when compress=None or no magic header found). LMK if you want expire() called elsewhere instead.

